// Lending iterator: items borrow from self for 'next
trait LendingIter {
    type Item<'next> where Self: 'next;
    fn next(&mut self) -> Option<Self::Item<'_>>;
}

struct WindowIter<'data> {
    data: &'data [i32],
    size: usize,
    pos: usize,
}

impl<'data> LendingIter for WindowIter<'data> {
    type Item<'next> = &'next [i32] where Self: 'next;

    fn next(&mut self) -> Option<&[i32]> {
        if self.pos + self.size > self.data.len() { return None; }
        let window = &self.data[self.pos..self.pos + self.size];
        self.pos += 1;
        Some(window)
    }
}

fn main() {
    let data = [1i32, 2, 3, 4, 5];
    let mut iter = WindowIter { data: &data, size: 3, pos: 0 };
    while let Some(window) = iter.next() {
        println!("{:?}", window);
    }
}
